// ============================================================================
// Multi-Topic Newsletter - Code Node (Single Query Version)
// ============================================================================
// All data comes from vw_newsletter_multi_topic_llm (combined view)
// ============================================================================

const webhookBody = $('Webhook').first().json.body;
const data = $('Supabase - Get All Data').first().json || {};

// Default conversation state
const defaultState = {
  phase: 'topic_selection',
  selected_topics: [],
  current_topic_index: 0,
  current_question_index: 0,
  answers: {}
};

return [
  {
    json: {
      // Webhook identifiers
      user_id: webhookBody.user_id,
      user_mssg: webhookBody.user_mssg,
      session_id: webhookBody.session_id,
      agent_name: webhookBody.agent_name,
      timestamp_of_call_made: webhookBody.timestamp_of_call_made,
      request_id: webhookBody.request_id,

      // KB data (from combined view)
      knowledge_base: data.knowledge_base || '',
      knowledge_base_summary: (data.knowledge_base || '').substring(0, 2000),
      website_url: data.website_url || '',
      website_icon: data.favicon_url || '',
      communication_tone: data.communication_tone || 'professional',
      newsletter_instructions: data.newsletter_questions || '',

      // Topics data (from combined view)
      available_topics_display: data.available_topics_display || '',
      available_topics_text: data.available_topics_text || '',
      topics_with_questions: JSON.stringify(data.topics_with_questions || [], null, 2),
      topics_questions_formatted: data.topics_questions_formatted || '',
      topic_code_map: data.topic_code_map || {},
      total_topics: data.total_topics || 7,

      // Conversation state
      conversation_state: JSON.stringify(defaultState, null, 2)
    }
  }
];

