parameters.jsCode:
// Prepare data for newsletter generation
const codeData = $('Code - Prepare Data').first().json;
const agentOutput = $('AI Agent - Conversation').first().json.output;

// Parse state to get all answers
const state = agentOutput.state || {};
const allAnswers = state.answers || {};
const selectedTopics = state.selected_topics || [];

// Parse topics_with_questions to get topic details
let topicsWithQuestions = [];
try {
  topicsWithQuestions = JSON.parse(codeData.topics_with_questions);
} catch (e) {
  topicsWithQuestions = [];
}

// Map selected topics to their full details
const topicDetails = selectedTopics.map(topicCode => {
  const topicInfo = topicsWithQuestions.find(t => t.topic_code === topicCode) || {};
  return {
    topic_code: topicCode,
    topic_name: topicInfo.topic_name || topicCode,
    emoji: topicInfo.emoji || '📧',
    is_hero: selectedTopics.indexOf(topicCode) === 0,
    answers: allAnswers[topicCode] || {},
    questions: topicInfo.questions || []
  };
});

return [
  {
    json: {
      // Pass through identifiers
      user_id: codeData.user_id,
      session_id: codeData.session_id,
      request_id: codeData.request_id,

      // Company context
      website_url: codeData.website_url,
      website_icon: codeData.website_icon,
      communication_tone: codeData.communication_tone,
      knowledge_base: codeData.knowledge_base,
      newsletter_instructions: codeData.newsletter_instructions,

      // Selected topics and answers
      selected_topics: selectedTopics,
      all_answers: JSON.stringify(allAnswers, null, 2),
      topic_details: JSON.stringify(topicDetails, null, 2)
    }
  }
];

// Clean the HTML output
return items.map(item => {
  let raw = item.json.output;

  if (!raw) {
    return { json: { error: 'No output field found' } };
  }

  // Remove markdown code block markers
  const cleaned = raw
    .replace(/^```html\s*/, '')
    .replace(/^```\s*/, '')
    .replace(/```$/, '')
    .trim();

  return {
    json: {
      Newsletter_HTML: cleaned
    }
  };
});
